import React, { useState, useEffect } from 'react';
import { useNavigate } from 'react-router-dom';
import { getAllDoctors, deleteDoctor, addReview, getReviews } from '../services/api';
import { useAuth } from '../context/AuthContext';
import Navbar from '../components/Navbar';

const SPECS = ['All', 'Cardiology', 'Neurology', 'Orthopedics', 'Dermatology', 'Pediatrics', 'General Medicine'];

const specColors = {
  Cardiology: { bg: '#fef2f2', color: '#dc2626', icon: '🫀' },
  Neurology: { bg: '#f0fdf4', color: '#16a34a', icon: '🧠' },
  Orthopedics: { bg: '#fff7ed', color: '#ea580c', icon: '🦴' },
  Dermatology: { bg: '#fdf4ff', color: '#a21caf', icon: '✨' },
  Pediatrics: { bg: '#eff6ff', color: '#2563eb', icon: '👶' },
  'General Medicine': { bg: '#f0fdfa', color: '#0d9488', icon: '🩺' },
};

const Doctors = () => {
  const { user } = useAuth();
  const navigate = useNavigate();

  const [doctors, setDoctors] = useState([]);
  const [search, setSearch] = useState('');
  const [specFilter, setSpecFilter] = useState('All');
  const [loading, setLoading] = useState(true);

  useEffect(() => {
    getAllDoctors()
      .then(res => setDoctors(res.data))
      .catch(console.log)
      .finally(() => setLoading(false));
  }, []);

  const handleDelete = async (id) => {
    if (!window.confirm('Delete doctor?')) return;
    await deleteDoctor(id);
    setDoctors(doctors.filter(d => d._id !== id));
  };

  const filtered = doctors.filter(d => {
    const name = d.userId?.name?.toLowerCase() || '';
    const spec = d.specialization?.toLowerCase() || '';
    const q = search.toLowerCase();

    return (specFilter === 'All' || d.specialization === specFilter) &&
           (!q || name.includes(q) || spec.includes(q));
  });

  return (
    <div style={S.page}>
      <Navbar />

      <div style={S.wrap}>
        <h1 style={S.title}>Our Doctors</h1>

        <input
          placeholder="Search doctor..."
          value={search}
          onChange={(e) => setSearch(e.target.value)}
          style={S.input}
        />

        <div style={S.filters}>
          {SPECS.map(s => (
            <button key={s}
              style={{ ...S.pill, ...(specFilter === s ? S.activePill : {}) }}
              onClick={() => setSpecFilter(s)}>
              {s}
            </button>
          ))}
        </div>

        {loading ? <p>Loading...</p> : (
          <div style={S.grid}>
            {filtered.map(d => {
              const sc = specColors[d.specialization] || specColors['General Medicine'];

              return (
                <div key={d._id} style={{ ...S.card, borderTop: `4px solid ${sc.color}` }}>

                  <h3>{d.userId?.name}</h3>

                  <p style={{ color: sc.color }}>
                    {sc.icon} {d.specialization}
                  </p>

                  <p>⭐ {d.rating}</p>
                  <p>🎓 {d.experience} yrs</p>
                  <p>₹{d.consultationFee}</p>

                  <div style={S.btns}>
                    {user?.role === 'patient' && (
                      <button style={S.bookBtn} onClick={() => navigate('/book')}>
                        Book
                      </button>
                    )}

                    {user?.role === 'admin' && (
                      <button style={S.delBtn} onClick={() => handleDelete(d._id)}>
                        Delete
                      </button>
                    )}
                  </div>

                  {/* ⭐ REVIEW FEATURE */}
                  <ReviewForm doctorId={d._id} userId={user?._id} />
                  <ReviewList doctorId={d._id} />
                </div>
              );
            })}
          </div>
        )}
      </div>
    </div>
  );
};

//////////////////////////////////////////////////
// ⭐ REVIEW FORM
//////////////////////////////////////////////////
const ReviewForm = ({ doctorId, userId }) => {
  const [rating, setRating] = useState(0);
  const [comment, setComment] = useState('');

  const submit = async () => {
    if (!rating) return alert("Select rating");

    await addReview({ doctorId, rating, comment, userId });

    alert("Review added!");
    setRating(0);
    setComment('');
  };

  return (
    <div style={S.reviewBox}>
      <h4>Add Review</h4>

      <div>
        {[1,2,3,4,5].map(s => (
          <span key={s}
            onClick={() => setRating(s)}
            style={{
              cursor: 'pointer',
              color: s <= rating ? '#fbbf24' : '#ddd',
              fontSize: 20
            }}>
            ★
          </span>
        ))}
      </div>

      <textarea
        placeholder="Write your experience..."
        value={comment}
        onChange={(e) => setComment(e.target.value)}
        style={S.textarea}
      />

      <button style={S.submitBtn} onClick={submit}>Submit</button>
    </div>
  );
};

//////////////////////////////////////////////////
// 📋 REVIEW LIST
//////////////////////////////////////////////////
const ReviewList = ({ doctorId }) => {
  const [reviews, setReviews] = useState([]);

  useEffect(() => {
    getReviews(doctorId).then(res => setReviews(res.data));
  }, [doctorId]);

  return (
    <div style={S.reviewList}>
      <h4>Patient Reviews</h4>

      {reviews.length === 0 ? (
        <p>No reviews yet</p>
      ) : (
        reviews.map(r => (
          <div key={r._id} style={S.reviewItem}>
            <b>{r.userId?.name}</b>
            <div style={{ color: '#fbbf24' }}>
              {"★".repeat(r.rating)}{"☆".repeat(5 - r.rating)}
            </div>
            <p>{r.comment}</p>
          </div>
        ))
      )}
    </div>
  );
};

//////////////////////////////////////////////////
// 🎨 STYLES
//////////////////////////////////////////////////
const S = {
  page: { padding: 20, background: '#f8fafc', minHeight: '100vh' },
  wrap: { maxWidth: 1100, margin: 'auto' },
  title: { marginBottom: 10 },

  input: {
    width: '100%',
    padding: 10,
    marginBottom: 15,
    borderRadius: 8,
    border: '1px solid #ddd'
  },

  filters: { marginBottom: 15 },

  pill: {
    padding: '6px 12px',
    marginRight: 6,
    border: '1px solid #ddd',
    borderRadius: 20,
    cursor: 'pointer'
  },

  activePill: {
    background: '#6366f1',
    color: '#fff'
  },

  grid: {
    display: 'grid',
    gridTemplateColumns: 'repeat(3,1fr)',
    gap: 20
  },

  card: {
    background: '#fff',
    padding: 15,
    borderRadius: 12,
    boxShadow: '0 2px 6px rgba(0,0,0,0.1)'
  },

  btns: { display: 'flex', gap: 10, marginTop: 10 },

  bookBtn: {
    background: '#6366f1',
    color: '#fff',
    border: 'none',
    padding: '6px 12px',
    borderRadius: 6,
    cursor: 'pointer'
  },

  delBtn: {
    border: '1px solid red',
    color: 'red',
    padding: '6px 12px',
    borderRadius: 6,
    cursor: 'pointer'
  },

  reviewBox: {
    marginTop: 15,
    padding: 10,
    borderTop: '1px solid #eee'
  },

  textarea: {
    width: '100%',
    marginTop: 8,
    padding: 8,
    borderRadius: 6,
    border: '1px solid #ddd'
  },

  submitBtn: {
    marginTop: 8,
    background: '#6366f1',
    color: '#fff',
    border: 'none',
    padding: '6px 12px',
    borderRadius: 6,
    cursor: 'pointer'
  },

  reviewList: {
    marginTop: 10
  },

  reviewItem: {
    borderTop: '1px solid #eee',
    paddingTop: 6,
    marginTop: 6
  }
};

export default Doctors;
